var surah046 = {
  number: 46,
  nameArabic: "al-Ahqaf",
  nameEnglish: "Al-Ahqaf",
  meaning: "The Wind-Curved Sandhills",
  totalAyahs: 35,
  ayahs: [
    { number: 1, arabic: "حمٓ", transliteration: "Hameem", transliterationB: "Haa-Meeeem", english: "Ha-Mim", romanUrdu: "Haa meem" },
    { number: 2, arabic: "تَنزِيلُ ٱلْكِتَٰبِ مِنَ ٱللَّهِ ٱلْعَزِيزِ ٱلْحَكِيمِ", transliteration: "Tanzeelu alkitabi mina Allahi alAAazeezi alhakeemi", transliterationB: "Tanzeelul Kitaabi minal laahil-'Azeezil Hakeem", english: "The Revelation of the Book is from Allah the Exalted in Power, Full of Wisdom", romanUrdu: "Is kitaab ka nuzul Allah zabardast aur dana ki taraf se hai" },
    { number: 3, arabic: "مَا خَلَقْنَا ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَآ إِلَّا بِٱلْحَقِّ وَأَجَلٍۢ مُّسَمًّۭى ۚ وَٱلَّذِينَ كَفَرُوا۟ عَمَّآ أُنذِرُوا۟ مُعْرِضُونَ", transliteration: "Ma khalaqna alssamawati waalarda wama baynahuma illa bialhaqqi waajalin musamman waallatheena kafaroo AAamma onthiroo muAAridoona", transliterationB: "Maa khalaqnas samaawaati wal arda wa maa bainahumaaa illaa bilhaqqi wa ajalim musammaa; wallazeena kafaroo 'ammaaa unziroo mu'ridoon", english: "We created not the heavens and the earth and all between them but for just ends, and for a Term Appointed: But those who reject Faith turn away from that whereof they are warned", romanUrdu: "Humne zameen aur aasmaano ko aur un saari cheezon ko jo unke darmiyan hain bar-haqq aur ek muddat e khaas ke taayun ke saath paida kiya hai. Magar yeh kaafir log us haqeeqat se mooh moade hue hain jisse unko khabardar kiya gaya hai" },
    { number: 4, arabic: "قُلْ أَرَءَيْتُم مَّا تَدْعُونَ مِن دُونِ ٱللَّهِ أَرُونِى مَاذَا خَلَقُوا۟ مِنَ ٱلْأَرْضِ أَمْ لَهُمْ شِرْكٌۭ فِى ٱلسَّمَٰوَٰتِ ۖ ٱئْتُونِى بِكِتَٰبٍۢ مِّن قَبْلِ هَٰذَآ أَوْ أَثَٰرَةٍۢ مِّنْ عِلْمٍ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Qul araaytum ma tadAAoona min dooni Allahi aroonee matha khalaqoo mina alardi am lahum shirkun fee alssamawati eetoonee bikitabin min qabli hatha aw atharatin min AAilmin in kuntum sadiqeena", transliterationB: "Qul ara'aytum maa tad'oona min doonil laahi aroonee maazaa khalaqoo minal ardi am lahum shirkun fis samaawaati eetoonee bi kitaabim min qabli haazaaa aw asaaratim min 'ilmin in kuntum saadiqeen", english: "Say: \"Do ye see what it is ye invoke besides Allah? Show me what it is they have created on earth, or have they a share in the heavens bring me a book (revealed) before this, or any remnant of knowledge (ye may have), if ye are telling the truth", romanUrdu: "Aey Nabi, inse kaho, “kabhi tumne aankhein khol kar dekha bhi ke woh hastiyan hain kya jinhein tum khuda ko chodh kar pukarte ho? Zara mujhey dikhao to sahih ke zameen mein unhon ne kya paida kiya hai, ya aasmano ki takhleeq o tadbeer mein unka kya hissa hai. Issey pehle aayi hui kitaab ya ilm ka koi baqiyya (in aqaid ke sabot mein) tumhare paas ho to wahi le aao agar tum sacche ho”" },
    { number: 5, arabic: "وَمَنْ أَضَلُّ مِمَّن يَدْعُوا۟ مِن دُونِ ٱللَّهِ مَن لَّا يَسْتَجِيبُ لَهُۥٓ إِلَىٰ يَوْمِ ٱلْقِيَٰمَةِ وَهُمْ عَن دُعَآئِهِمْ غَٰفِلُونَ", transliteration: "Waman adallu mimman yadAAoo min dooni Allahi man la yastajeebu lahu ila yawmi alqiyamati wahum AAan duAAaihim ghafiloona", transliterationB: "Wa man adallu mimmany yad'oo min doonil laahi mallaa yastajeebu lahooo ilaa Yawmil Qiyaamati wa hum'an du'aaa'ihim ghaafiloon", english: "And who is more astray than one who invokes besides Allah, such as will not answer him to the Day of Judgment, and who (in fact) are unconscious of their call (to them)", romanUrdu: "Aakhir us shaks se zyada behka hua insaan aur kaun hoga jo Allah ko chodh kar unko pukare jo qayamat tak usey jawab nahin de sakte, balke issey bhi bekhabar hain ke pukarne waley unko pukar rahey hain" },
    { number: 6, arabic: "وَإِذَا حُشِرَ ٱلنَّاسُ كَانُوا۟ لَهُمْ أَعْدَآءًۭ وَكَانُوا۟ بِعِبَادَتِهِمْ كَٰفِرِينَ", transliteration: "Waitha hushira alnnasu kanoo lahum aAAdaan wakanoo biAAibadatihim kafireena", transliterationB: "Wa izaa hushiran naasu kaanoo lahum a'daaa'anw wa kaanoo bi'ibaadatihim kaafireen", english: "And when mankind are gathered together (at the Resurrection), they will be hostile to them and reject their worship (altogether)", romanUrdu: "Aur jab tamam Insan jamaa kiye jayenge us waqt woh apne pukarne walon ke dushman aur unki ibadat ke munkir honge" },
    { number: 7, arabic: "وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَٰتُنَا بَيِّنَٰتٍۢ قَالَ ٱلَّذِينَ كَفَرُوا۟ لِلْحَقِّ لَمَّا جَآءَهُمْ هَٰذَا سِحْرٌۭ مُّبِينٌ", transliteration: "Waitha tutla AAalayhim ayatuna bayyinatin qala allatheena kafaroo lilhaqqi lamma jaahum hatha sihrun mubeenun", transliterationB: "Wa izaa tutlaa 'alaihim Aayaatunaa baiyinaatin qaalal lazeena kafaroo lilhaqqi lammaa jaaa'ahum haazaa sihrum mubeen", english: "When Our Clear Signs are rehearsed to them, the Unbelievers say, of the Truth when it comes to them: \"This is evident sorcery", romanUrdu: "In logon ko jab hamari saaf saaf aayat sunayi jaati hain aur haqq inke saamne aa jata hai to yeh kafir log uske mutaaliq kehte hain ke yeh to khula jaadu hai" },
    { number: 8, arabic: "أَمْ يَقُولُونَ ٱفْتَرَىٰهُ ۖ قُلْ إِنِ ٱفْتَرَيْتُهُۥ فَلَا تَمْلِكُونَ لِى مِنَ ٱللَّهِ شَيْـًٔا ۖ هُوَ أَعْلَمُ بِمَا تُفِيضُونَ فِيهِ ۖ كَفَىٰ بِهِۦ شَهِيدًۢا بَيْنِى وَبَيْنَكُمْ ۖ وَهُوَ ٱلْغَفُورُ ٱلرَّحِيمُ", transliteration: "Am yaqooloona iftarahu qul ini iftaraytuhu fala tamlikoona lee mina Allahi shayan huwa aAAlamu bima tufeedoona feehi kafa bihi shaheedan baynee wabaynakum wahuwa alghafooru alrraheemu", transliterationB: "Am yaqooloonaf taraahu qul inif taraituhoo falaa tamlikoona lee minal laahi shai'an Huwa a'lamu bimaa tufeedoona feehi kafaa bihee shaheedam bainee wa bainakum wa Huwal Ghafoorur Raheem", english: "Or do they say, \"He has forged it\"? Say: \"Had I forged it, then can ye obtain no single (blessing) for me from Allah. He knows best of that whereof ye talk (so glibly)! Enough is He for a witness between me and you! And he is Oft-Forgiving, Most Merciful", romanUrdu: "Kya unka kehna yeh hai ke Rasool ne isey khud ghadh (fabricated) liya hai? Inse kaho “ agar maine isey khud ghadh (fabricated) liya hai to tum mujhey khuda ki pakad se kuch bhi na bacha sakogey. Jo baatein tum banate ho Allah unko khoob jaanta hai, mere aur tumhare darmiyaan wahi gawahi dene ke liye kaafi hai, aur woh bada darguzar karne wala aur Raheem hai”" },
    { number: 9, arabic: "قُلْ مَا كُنتُ بِدْعًۭا مِّنَ ٱلرُّسُلِ وَمَآ أَدْرِى مَا يُفْعَلُ بِى وَلَا بِكُمْ ۖ إِنْ أَتَّبِعُ إِلَّا مَا يُوحَىٰٓ إِلَىَّ وَمَآ أَنَا۠ إِلَّا نَذِيرٌۭ مُّبِينٌۭ", transliteration: "Qul ma kuntu bidAAan mina alrrusuli wama adree ma yufAAalu bee wala bikum in attabiAAu illa ma yooha ilayya wama ana illa natheerun mubeenun", transliterationB: "Qul maa kuntu bid'am minal Rusuli wa maaa adreee ma yuf'alu bee wa laa bikum in attabi'u illaa maa yoohaaa ilaiya ya maaa ana illaa nazeerum mubeen", english: "Say: \"I am no bringer of new-fangled doctrine among the messengers, nor do I know what will be done with me or with you. I follow but that which is revealed to me by inspiration; I am but a Warner open and clear", romanUrdu: "Inse kaho “main koi nirala Rasool to nahin hoon, main nahin jaanta ke kal tumhare saath kya hona hai aur mere saath kya. Main to sirf us wahee (revelation) ki pairwi karta hoon jo mere paas bheji jaati hai aur main ek saaf saaf khabardar kardene wale ke siwa kuch nahin hoon”" },
    { number: 10, arabic: "قُلْ أَرَءَيْتُمْ إِن كَانَ مِنْ عِندِ ٱللَّهِ وَكَفَرْتُم بِهِۦ وَشَهِدَ شَاهِدٌۭ مِّنۢ بَنِىٓ إِسْرَٰٓءِيلَ عَلَىٰ مِثْلِهِۦ فَـَٔامَنَ وَٱسْتَكْبَرْتُمْ ۖ إِنَّ ٱللَّهَ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّٰلِمِينَ", transliteration: "Qul araaytum in kana min AAindi Allahi wakafartum bihi washahida shahidun min banee israeela AAala mithlihi faamana waistakbartum inna Allaha la yahdee alqawma alththalimeena", transliterationB: "Qul ara'aytum in kaana min 'indil laahi wa kafartum bihee wa shahida shaahidum mim Banee Israaa'eela 'alaa mislihee fa aamana wastak bartum innal laaha laa yahdil qawmaz zaalimeen", english: "Say: \"See ye? If (this teaching) be from Allah, and ye reject it, and a witness from among the Children of Israel testifies to its similarity (with earlier scripture), and has believed while ye are arrogant, (how unjust ye are!) truly, Allah guides not a people unjust", romanUrdu: "Aey Nabi, inse kaho “ kabhi tumne socha bhi ke agar yeh kalaam Allah hi ki taraf se hua aur tum ne iska inkar kardiya ( to tumhara kya anjaam hoga)?Aur is jaise ek kalaam par to bani Israel ka ek gawah shahadat bhi de chukka hai. Woh imaan le aaya aur tum apne ghamand (arrogant) mein padey rahey. Aise zaalimon ko Allah hidayat nahin diya karta”" },
    { number: 11, arabic: "وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لِلَّذِينَ ءَامَنُوا۟ لَوْ كَانَ خَيْرًۭا مَّا سَبَقُونَآ إِلَيْهِ ۚ وَإِذْ لَمْ يَهْتَدُوا۟ بِهِۦ فَسَيَقُولُونَ هَٰذَآ إِفْكٌۭ قَدِيمٌۭ", transliteration: "Waqala allatheena kafaroo lillatheena amanoo law kana khayran ma sabaqoona ilayhi waith lam yahtadoo bihi fasayaqooloona hatha ifkun qadeemun", transliterationB: "Wa qaalal lazeena kafaroo lillazeena aamanoo law kaana khairam maa sabaqoonaaa ilyh; wa iz lam yahtadoo bihee fasa yaqooloona haazaaa ifkun qadeem", english: "The Unbelievers say of those who believe: \"If (this Message) were a good thing, (such men) would not have gone to it first, before us!\" And seeing that they guide not themselves thereby, they will say, \"this is an (old,) falsehood", romanUrdu: "Jin logon ne maan-ne se inkar kardiya hai woh imaan laney walon ke mutaaliq kehte hain “ke agar is kitaab ko maan lena koi accha kaam hota to yeh log is maamle mein humse sabaqat na leja sakte thay”. Chunke inhon ne usse hidayat na paayi is liye ab yeh zaroor kahenge ke yeh to purana jhoot hai" },
    { number: 12, arabic: "وَمِن قَبْلِهِۦ كِتَٰبُ مُوسَىٰٓ إِمَامًۭا وَرَحْمَةًۭ ۚ وَهَٰذَا كِتَٰبٌۭ مُّصَدِّقٌۭ لِّسَانًا عَرَبِيًّۭا لِّيُنذِرَ ٱلَّذِينَ ظَلَمُوا۟ وَبُشْرَىٰ لِلْمُحْسِنِينَ", transliteration: "Wamin qablihi kitabu moosa imaman warahmatan wahatha kitabun musaddiqun lisanan AAarabiyyan liyunthira allatheena thalamoo wabushra lilmuhsineena", transliterationB: "Wa min qablihee kitaabu Moosaaa imaamanw-wa rahmah; wa haazaa Kitaabum musad diqul lisaanan 'Arabiyyal liyunziral lazeena zalamoo wa bushraa lilmuhsineen", english: "And before this, was the Book of Moses as a guide and a mercy: And this Book confirms (it) in the Arabic tongue; to admonish the unjust, and as Glad Tidings to those who do right", romanUrdu: "Halaanke isse pehle Moosa ki kitaab rehnuma aur rehmat bankar aa chuki hai, aur yeh kitaab uski tasdeeq karne wali zubaan-e-arabi mein aayi hai taake zaalimon ko mutanabbe (warn) karde aur neik rawish ikhtiyar karne walon ko basharat de de" },
    { number: 13, arabic: "إِنَّ ٱلَّذِينَ قَالُوا۟ رَبُّنَا ٱللَّهُ ثُمَّ ٱسْتَقَٰمُوا۟ فَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", transliteration: "Inna allatheena qaloo rabbuna Allahu thumma istaqamoo fala khawfun AAalayhim wala hum yahzanoona", transliterationB: "Innal lazeena qaaloo Rabbunal laahu summas taqaamoo falaa khawfun 'alaihim wa laahum yahzanoon", english: "Verily those who say, \"Our Lord is Allah,\" and remain firm (on that Path),- on them shall be no fear, nor shall they grieve", romanUrdu: "Yakeenan jin logon ne kehdiya ke Allah hi hamara Rubb hai, phir us par jamm gaye, unke liye na koi khauff hai aur na woh ghamgheen hongey" },
    { number: 14, arabic: "أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلْجَنَّةِ خَٰلِدِينَ فِيهَا جَزَآءًۢ بِمَا كَانُوا۟ يَعْمَلُونَ", transliteration: "Olaika ashabu aljannati khalideena feeha jazaan bima kanoo yaAAmaloona", transliterationB: "Ulaaa'ika Ashabul Jannati khaalideena feehaa jazaaa'am bimaa kaano ya'maloon", english: "Such shall be Companions of the Gardens, dwelling therein (for aye): a recompense for their (good) deeds", romanUrdu: "Aise sab log Jannat mein jaane waley hain. Jahan woh hamesha rahenge apne un aamal ke badle jo woh duniya mein karte rahey hain" },
    { number: 15, arabic: "وَوَصَّيْنَا ٱلْإِنسَٰنَ بِوَٰلِدَيْهِ إِحْسَٰنًا ۖ حَمَلَتْهُ أُمُّهُۥ كُرْهًۭا وَوَضَعَتْهُ كُرْهًۭا ۖ وَحَمْلُهُۥ وَفِصَٰلُهُۥ ثَلَٰثُونَ شَهْرًا ۚ حَتَّىٰٓ إِذَا بَلَغَ أَشُدَّهُۥ وَبَلَغَ أَرْبَعِينَ سَنَةًۭ قَالَ رَبِّ أَوْزِعْنِىٓ أَنْ أَشْكُرَ نِعْمَتَكَ ٱلَّتِىٓ أَنْعَمْتَ عَلَىَّ وَعَلَىٰ وَٰلِدَىَّ وَأَنْ أَعْمَلَ صَٰلِحًۭا تَرْضَىٰهُ وَأَصْلِحْ لِى فِى ذُرِّيَّتِىٓ ۖ إِنِّى تُبْتُ إِلَيْكَ وَإِنِّى مِنَ ٱلْمُسْلِمِينَ", transliteration: "Wawassayna alinsana biwalidayhi ihsanan hamalathu ommuhu kurhan wawadaAAathu kurhan wahamluhu wafisaluhu thalathoona shahran hatta itha balagha ashuddahu wabalagha arbaAAeena sanatan qala rabbi awziAAnee an ashkura niAAmataka allatee anAAamta AAalayya waAAala walidayya waan aAAmala salihan tardahu waaslih lee fee thurriyyatee innee tubtu ilayka wainnee mina almuslimeena", transliterationB: "Wa wassainal insaana biwaalidaihi ihsaanan hamalathu ummuhoo kurhanw-wa wada'athu kurhanw wa hamluhoo wa fisaaluhoo salaasoona shahraa; hattaaa izaa balagha ashuddahoo wa balagho arba'eena sanatan qaala Rabbi aqzi'neee an ashkura ni'matakal lateee an'amta 'alaiya wa 'alaa waalidaiya wa an a'mala saalihan tardaahu wa aslih lee fee zurriyyatee innee tubtu ilaika wa innee minal muslimeen", english: "We have enjoined on man kindness to his parents: In pain did his mother bear him, and in pain did she give him birth. The carrying of the (child) to his weaning is (a period of) thirty months. At length, when he reaches the age of full strength and attains forty years, he says, \"O my Lord! Grant me that I may be grateful for Thy favour which Thou has bestowed upon me, and upon both my parents, and that I may work righteousness such as Thou mayest approve; and be gracious to me in my issue. Truly have I turned to Thee and truly do I bow (to Thee) in Islam", romanUrdu: "Humne Insan ko hidayat ki ke woh apne walidain ke saath neik bartaao karey. Uski maa ne mushakkat utha kar usey pait mein rakkha aur mushakkat utha kar hi usko jana(delivered). Aur uske hamal aur doodh chudane mein tees (thirty) mahine lag gaye. Yahan tak ke jab woh apni puri taaqat ko pahuncha aur chaalis(forty) saal ka ho gaya to usne kaha “Aey mere Rubb mujhey taufiq de ke main teri un niyamaton ka shukar ada karoon jo tu ne mujhey aur mere walidain ko ata famayi, aur aisa neik amal karoon jis se tu raazi ho, aur meri aulad ko bhi neik bana kar mujhey sukh de, mein tere huzoor tawbah karta hoon aur taabe farmaan (muslim)bandon mein se hoon”" },
    { number: 16, arabic: "أُو۟لَٰٓئِكَ ٱلَّذِينَ نَتَقَبَّلُ عَنْهُمْ أَحْسَنَ مَا عَمِلُوا۟ وَنَتَجَاوَزُ عَن سَيِّـَٔاتِهِمْ فِىٓ أَصْحَٰبِ ٱلْجَنَّةِ ۖ وَعْدَ ٱلصِّدْقِ ٱلَّذِى كَانُوا۟ يُوعَدُونَ", transliteration: "Olaika allatheena nataqabbalu AAanhum ahsana ma AAamiloo wanatajawazu AAan sayyiatihim fee ashabi aljannati waAAda alssidqi allathee kanoo yooAAadoona", transliterationB: "Ulaaa'ikal lazeena nata qabbalu 'anhum ahsana maa 'amiloo wa natajaawazu 'an saiyiaatihim feee Ashaabil jannati Wa'das sidqil lazee kaanoo yoo'adoon", english: "Such are they from whom We shall accept the best of their deeds and pass by their ill deeds: (They shall be) among the Companions of the Garden: a promise! of truth, which was made to them (in this life)", romanUrdu: "Is tarah ke logon se hum unke behtreen aamal ko qabool karte hain aur unki buraiyon se darguzar kar jaate hain. Yeh jannati logon mein shamil hongey us sacche waade ke mutaabiq jo insey kya jaata raha hai" },
    { number: 17, arabic: "وَٱلَّذِى قَالَ لِوَٰلِدَيْهِ أُفٍّۢ لَّكُمَآ أَتَعِدَانِنِىٓ أَنْ أُخْرَجَ وَقَدْ خَلَتِ ٱلْقُرُونُ مِن قَبْلِى وَهُمَا يَسْتَغِيثَانِ ٱللَّهَ وَيْلَكَ ءَامِنْ إِنَّ وَعْدَ ٱللَّهِ حَقٌّۭ فَيَقُولُ مَا هَٰذَآ إِلَّآ أَسَٰطِيرُ ٱلْأَوَّلِينَ", transliteration: "Waallathee qala liwalidayhi offin lakuma ataAAidaninee an okhraja waqad khalati alquroonu min qablee wahuma yastagheethani Allaha waylaka amin inna waAAda Allahi haqqun fayaqoolu ma hatha illa asateeru alawwaleena", transliterationB: "Wallazee qaala liwaali daihi uffil lakumaaa ata'idanineee an ukhraja wa qad khalatil quroonu min qablee wa humaa yastagheesaanil laaha wailaka aamin inna wa'dal laahi haqq, fa yaqoolu maa haazaaa illaaa asaateerul awwaleen", english: "But (there is one) who says to his parents, \"Fie on you! Do ye hold out the promise to me that I shall be raised up, even though generations have passed before me (without rising again)?\" And they two seek Allah's aid, (and rebuke the son): \"Woe to thee! Have faith! for the promise of Allah is true.\" But he says, \"This is nothing but tales of the ancients", romanUrdu: "Aur jis shaks ne apne waldain se kaha “ Uff, tang kar diya tumne” kya tum mujhe yeh khauff dilate ho ke main marne ke baad phir qabar se nikala jaunga halanke mujh se pehle bahut si nasalein(generations) guzar chuki hain ( unmein se to koi uth kar na aaya)”Maa aur baap Allah ki duhayi dekar kehte hain “ arey badnaseeb ,maan ja , Allah ka waada saccha hai”. Magar woh kehta hai “ yeh sab agle waqton ki farsuda(fables) kahaniyan hai”" },
    { number: 18, arabic: "أُو۟لَٰٓئِكَ ٱلَّذِينَ حَقَّ عَلَيْهِمُ ٱلْقَوْلُ فِىٓ أُمَمٍۢ قَدْ خَلَتْ مِن قَبْلِهِم مِّنَ ٱلْجِنِّ وَٱلْإِنسِ ۖ إِنَّهُمْ كَانُوا۟ خَٰسِرِينَ", transliteration: "Olaika allatheena haqqa AAalayhimu alqawlu fee umamin qad khalat min qablihim mina aljinni waalinsi innahum kanoo khasireena", transliterationB: "Ulaaa'ikal lazeena haqqa 'alaihimul qawlu feee umamin qad khalat min qablihim minal jinni wal insi innahum kaanoo khaasireen", english: "Such are they against whom is proved the sentence among the previous generations of Jinns and men, that have passed away; for they will be (utterly) lost", romanUrdu: "Yeh woh log hain jinpar azaab ka faisla chaspan ho chuka hai. Insey pehle Jinno aur Insano ke jo toley(communities) (isi qumash ke) ho guzre hain unhi mein yeh bhi ja shamil hongey. Beshak yeh ghatey(loss) mein reh janey wale log hain" },
    { number: 19, arabic: "وَلِكُلٍّۢ دَرَجَٰتٌۭ مِّمَّا عَمِلُوا۟ ۖ وَلِيُوَفِّيَهُمْ أَعْمَٰلَهُمْ وَهُمْ لَا يُظْلَمُونَ", transliteration: "Walikullin darajatun mimma AAamiloo waliyuwaffiyahum aAAmalahum wahum la yuthlamoona", transliterationB: "Wa likullin darajaatum mimmaa 'amiloo wa liyuwaf fiyahum a'maalahum wa hum laa yuzlamoon", english: "And to all are (assigned) degrees according to the deeds which they (have done), and in order that (Allah) may recompense their deeds, and no injustice be done to them", romanUrdu: "Dono girohon mein se har ek ke darje unke aamal ke lihaz se hain taa-ke Allah unke kiye ka pura pura badla unko de. Unpar zulm hargiz na kiya jaaye" },
    { number: 20, arabic: "وَيَوْمَ يُعْرَضُ ٱلَّذِينَ كَفَرُوا۟ عَلَى ٱلنَّارِ أَذْهَبْتُمْ طَيِّبَٰتِكُمْ فِى حَيَاتِكُمُ ٱلدُّنْيَا وَٱسْتَمْتَعْتُم بِهَا فَٱلْيَوْمَ تُجْزَوْنَ عَذَابَ ٱلْهُونِ بِمَا كُنتُمْ تَسْتَكْبِرُونَ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ وَبِمَا كُنتُمْ تَفْسُقُونَ", transliteration: "Wayawma yuAAradu allatheena kafaroo AAala alnnari athhabtum tayyibatikum fee hayatikumu alddunya waistamtaAAtum biha faalyawma tujzawna AAathaba alhooni bima kuntum tastakbiroona fee alardi bighayri alhaqqi wabima kuntum tafsuqoona", transliterationB: "Wa Yawma yu'radul lazeena kafaroo 'alan Naai azhabtum taiyibaatikum fee hayaatikumud dunyaa wastam ta'tum bihaa fal Yawma tujzawna 'azaabal hooni bimaa kuntum tastakbiroona fil ardi bighairil haqqi wa bimaa kuntum tafsuqoon", english: "And on the Day that the Unbelievers will be placed before the Fire, (It will be said to them): \"Ye received your good things in the life of the world, and ye took your pleasure out of them: but today shall ye be recompensed with a Penalty of humiliation: for that ye were arrogant on earth without just cause, and that ye (ever) transgressed", romanUrdu: "Phir jab yeh kaafir aag ke saame laa khade kiye jayenge to unse kaha jayega: “ tum apne hissay ki niyamatein apni duniya ki zindagi mein khatam kar chuke aur unka lutf tumne utha liya, ab jo takabbur tum zameen mein kisi haqq ke bagair karte rahe aur jo nafarmaniyan tumne ki unke padash mein aaj tumko zillat ka azaab diya jayega”" },
    { number: 21, arabic: "۞ وَٱذْكُرْ أَخَا عَادٍ إِذْ أَنذَرَ قَوْمَهُۥ بِٱلْأَحْقَافِ وَقَدْ خَلَتِ ٱلنُّذُرُ مِنۢ بَيْنِ يَدَيْهِ وَمِنْ خَلْفِهِۦٓ أَلَّا تَعْبُدُوٓا۟ إِلَّا ٱللَّهَ إِنِّىٓ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍ عَظِيمٍۢ", transliteration: "Waothkur akha AAadin ith anthara qawmahu bialahqafi waqad khalati alnnuthuru min bayni yadayhi wamin khalfihi alla taAAbudoo illa Allaha innee akhafu AAalaykum AAathaba yawmin AAatheemin", transliterationB: "Wazkur akhaa 'Aad, iz anzara qawmahoo bil Ahqaafi wa qad khalatin nuzuru mim baini yadaihi wa min khalfiheee allaa ta'budooo illal laaha inneee akhaafu 'alaikum 'azaaba Yawmin 'azeem", english: "Mention (Hud) one of 'Ad's (own) brethren: Behold, he warned his people about the winding Sand-tracts: but there have been warners before him and after him: \"Worship ye none other than Allah: Truly I fear for you the Penalty of a Mighty Day", romanUrdu: "Zara inhein Aad ke bhai (Hud) ka qissa sunao jabke usne ahqaf mein apni qaum ko khabardar kiya tha aur aise khabardar karne waley ussey pehle bhi guzar chuke thay aur uske baad bhi aate rahey ke “ Allah ke siwa kisi ki bandagi na karo , mujhe tumhare haqq mein ek baday haulnaak din ke azaab ka andesha hai”" },
    { number: 22, arabic: "قَالُوٓا۟ أَجِئْتَنَا لِتَأْفِكَنَا عَنْ ءَالِهَتِنَا فَأْتِنَا بِمَا تَعِدُنَآ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ", transliteration: "Qaloo ajitana litafikana AAan alihatina fatina bima taAAiduna in kunta mina alssadiqeena", transliterationB: "Qaaloo aji'tanaa litaa fikanaa 'an aalihatinaa faatinaa bimaa ta'idunaaa in kunta minas saadiqeen", english: "They said: \"Hast thou come in order to turn us aside from our gods? Then bring upon us the (calamity) with which thou dost threaten us, if thou art telling the truth", romanUrdu: "Unhon ne kaha “ kya tu isliye aaya hai ke humein behka kar hamare maboodon se bargashta kar de? Accha to le aa apna woh azaab jissey tu humein darata hai agar waqai tu saccha hai”" },
    { number: 23, arabic: "قَالَ إِنَّمَا ٱلْعِلْمُ عِندَ ٱللَّهِ وَأُبَلِّغُكُم مَّآ أُرْسِلْتُ بِهِۦ وَلَٰكِنِّىٓ أَرَىٰكُمْ قَوْمًۭا تَجْهَلُونَ", transliteration: "Qala innama alAAilmu AAinda Allahi waoballighukum ma orsiltu bihi walakinnee arakum qawman tajhaloona", transliterationB: "Qaala innamal 'ilmu indal laahi wa uballighukum maaa uriltu bihee wa laakinneee araakum qawman tajhaloon", english: "He said: \"The Knowledge (of when it will come) is only with Allah: I proclaim to you the mission on which I have been sent: But I see that ye are a people in ignorance", romanUrdu: "Usne kaha ke “iska ilm to Allah ko hai, main sirf woh paighaam tumhein pahuncha raha hoon jisey dekar mujhey bheja gaya hai. Magar main dekh raha hoon ke tumlog jahalat barat rahey ho”" },
    { number: 24, arabic: "فَلَمَّا رَأَوْهُ عَارِضًۭا مُّسْتَقْبِلَ أَوْدِيَتِهِمْ قَالُوا۟ هَٰذَا عَارِضٌۭ مُّمْطِرُنَا ۚ بَلْ هُوَ مَا ٱسْتَعْجَلْتُم بِهِۦ ۖ رِيحٌۭ فِيهَا عَذَابٌ أَلِيمٌۭ", transliteration: "Falamma raawhu AAaridan mustaqbila awdiyatihim qaloo hatha AAaridun mumtiruna bal huwa ma istaAAjaltum bihi reehun feeha AAathabun aleemun", transliterationB: "Falammaa ra awhu 'aaridam mustaqbila awdiyatihim qaaloo haazaa 'aaridum mumtirunaa; bal huwa masta'jaltum bihee reehun feehaa 'azaabun aleem", english: "Then, when they saw the (Penalty in the shape of) a cloud traversing the sky, coming to meet their valleys, they said, \"This cloud will give us rain!\" \"Nay, it is the (Calamity) ye were asking to be hastened!- A wind wherein is a Grievous Penalty", romanUrdu: "Phir jab unhon ne us azaab ko apni waadiyon (valleys) ki taraf aate dekha to kehne lagey “yeh badal hai jo humko sairaab kardega”. balke yeh wahi cheez hai jiske liye tum jaldi macha rahe thay, yeh hawa ka toofaan hai jismein dardnaak azaab chala aa raha hai" },
    { number: 25, arabic: "تُدَمِّرُ كُلَّ شَىْءٍۭ بِأَمْرِ رَبِّهَا فَأَصْبَحُوا۟ لَا يُرَىٰٓ إِلَّا مَسَٰكِنُهُمْ ۚ كَذَٰلِكَ نَجْزِى ٱلْقَوْمَ ٱلْمُجْرِمِينَ", transliteration: "Tudammiru kulla shayin biamri rabbiha faasbahoo la yura illa masakinuhum kathalika najzee alqawma almujrimeena", transliterationB: "Tudammiru kulla shai'im bi-amri Rabbihaa fa asbahoo laa yuraaa illaa masaakinuhum; kazaalika najzil qawmal mujrimeen", english: "Everything will it destroy by the command of its Lord!\" Then by the morning they - nothing was to be seen but (the ruins of) their houses! thus do We recompense those given to sin", romanUrdu: "Apne Rubb ke hukum se har cheez ko tabaah kar dalega”. Aakhir e kaar unka haal yeh hua ke unke rehne ke jaghon ke siwa wahan kuch nazar na aata tha. Is tarah hum mujrimon ko badla diya karte hain" },
    { number: 26, arabic: "وَلَقَدْ مَكَّنَّٰهُمْ فِيمَآ إِن مَّكَّنَّٰكُمْ فِيهِ وَجَعَلْنَا لَهُمْ سَمْعًۭا وَأَبْصَٰرًۭا وَأَفْـِٔدَةًۭ فَمَآ أَغْنَىٰ عَنْهُمْ سَمْعُهُمْ وَلَآ أَبْصَٰرُهُمْ وَلَآ أَفْـِٔدَتُهُم مِّن شَىْءٍ إِذْ كَانُوا۟ يَجْحَدُونَ بِـَٔايَٰتِ ٱللَّهِ وَحَاقَ بِهِم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ", transliteration: "Walaqad makkannahum feema in makkannakum feehi wajaAAalna lahum samAAan waabsaran waafidatan fama aghna AAanhum samAAuhum wala absaruhum wala afidatuhum min shayin ith kanoo yajhadoona biayati Allahi wahaqa bihim ma kanoo bihi yastahzioona", transliterationB: "Wa laqad makkannaahum feemaaa im makkannaakum feehi waj'alnaa lahum sam'anw wa absaaranw wa af'idatan famaaa aghnaa 'anhum samu'uhum wa laaa absaaruhum wa laaa af'idatuhum min shai'in iz kaanoo yajhadoona bi Aayaatil laahi wa haaqa bihim maa kaanoo bihee yastahzi'oon", english: "And We had firmly established them in a (prosperity and) power which We have not given to you (ye Quraish!) and We had endowed them with (faculties of) hearing, seeing, heart and intellect: but of no profit to them were their (faculties of) hearing, sight, and heart and intellect, when they went on rejecting the Signs of Allah; and they were (completely) encircled by that which they used to mock at", romanUrdu: "Unko humne woh kuch diya tha jo tum logon ko nahin diya hai. Unko humne kaan, aankehin aur dil sab kuch de rakkhe thay, magar na woh kaan unke kisi kaam aaye, na aankhein, na dil, kyunke woh Allah ki aayat ka inkar karte thay, aur usi cheez ke phair mein woh aa gaye jiska woh mazaak udate thay" },
    { number: 27, arabic: "وَلَقَدْ أَهْلَكْنَا مَا حَوْلَكُم مِّنَ ٱلْقُرَىٰ وَصَرَّفْنَا ٱلْءَايَٰتِ لَعَلَّهُمْ يَرْجِعُونَ", transliteration: "Walaqad ahlakna ma hawlakum mina alqura wasarrafna alayati laAAallahum yarjiAAoona", transliterationB: "Wa laqad ahlaknaa ma hawlakum minal quraa wa sarrafnal Aayaati la'allahum yarji'oon", english: "We destroyed aforetime populations round about you; and We have shown the Signs in various ways, that they may turn (to Us)", romanUrdu: "Tumhare gird o pesh ke ilakon mein bahut se bastiyon ko hum halaak kar chuke hain. Humne apni aayat bhej kar baar baar tarah tarah se unko samjhaya, shayad ke woh baaz aa jayein" },
    { number: 28, arabic: "فَلَوْلَا نَصَرَهُمُ ٱلَّذِينَ ٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ قُرْبَانًا ءَالِهَةًۢ ۖ بَلْ ضَلُّوا۟ عَنْهُمْ ۚ وَذَٰلِكَ إِفْكُهُمْ وَمَا كَانُوا۟ يَفْتَرُونَ", transliteration: "Falawla nasarahumu allatheena ittakhathoo min dooni Allahi qurbanan alihatan bal dalloo AAanhum wathalika ifkuhum wama kanoo yaftaroona", transliterationB: "Falaw laa nasarahumul lazeenat takhazoo min doonil laahi qurbaanan aalihatam bal dalloo 'anhum' wa zaalika ifkuhum wa maa kaanoo yaftaroon", english: "Why then was no help forthcoming to them from those whom they worshipped as gods, besides Allah, as a means of access (to Allah)? Nay, they left them in the lurch: but that was their falsehood and their invention", romanUrdu: "Phir kyun na un hastiyon ne unki madad ki jinhein Allah ko chodh kar unhon ne taqarrub-e-ilallah ka zariya samajhte huey maabood bana liya tha? Balke woh to unsey khoye gaye. Aur yeh tha unke jhoot aur un banawati aqeedon ka anjaam jo unhon ne ghadh rakkhe thay" },
    { number: 29, arabic: "وَإِذْ صَرَفْنَآ إِلَيْكَ نَفَرًۭا مِّنَ ٱلْجِنِّ يَسْتَمِعُونَ ٱلْقُرْءَانَ فَلَمَّا حَضَرُوهُ قَالُوٓا۟ أَنصِتُوا۟ ۖ فَلَمَّا قُضِىَ وَلَّوْا۟ إِلَىٰ قَوْمِهِم مُّنذِرِينَ", transliteration: "Waith sarafna ilayka nafaran mina aljinni yastamiAAoona alqurana falamma hadaroohu qaloo ansitoo falamma qudiya wallaw ila qawmihim munthireena", transliterationB: "Wa iz sarafinaaa ilaika nafaram minal jinni yastami'oonal Quraana falammaa hadaroohu qaalooo ansitoo falammaa qudiya wallaw ilaa qawmihim munzireen", english: "Behold, We turned towards thee a company of Jinns (quietly) listening to the Qur'an: when they stood in the presence thereof, they said, \"Listen in silence!\" When the (reading) was finished, they returned to their people, to warn (them of their sins)", romanUrdu: "(Aur woh waqiya bhi qabil e zikar hai) jab hum Jinno ke ek girooh ko tumhari taraf le aaye thay taa-ke Quran sunein. Jab woh us jagaah pahunche (jahan tum Quraan padh rahe thay) to unhon ne aapas mein kaha khamosh ho jao, phir jab woh padha ja chukka to woh khabardar karne walay ban kar apni qaum ki taraf palte(returned)" },
    { number: 30, arabic: "قَالُوا۟ يَٰقَوْمَنَآ إِنَّا سَمِعْنَا كِتَٰبًا أُنزِلَ مِنۢ بَعْدِ مُوسَىٰ مُصَدِّقًۭا لِّمَا بَيْنَ يَدَيْهِ يَهْدِىٓ إِلَى ٱلْحَقِّ وَإِلَىٰ طَرِيقٍۢ مُّسْتَقِيمٍۢ", transliteration: "Qaloo ya qawmana inna samiAAna kitaban onzila min baAAdi moosa musaddiqan lima bayna yadayhi yahdee ila alhaqqi waila tareeqin mustaqeemin", transliterationB: "Qaaloo yaa qawmanaaa innaa sami'naa Kitaaban unzila mim ba'di Moosa musaddiqal limaa baina yadihi yahdeee ilal haqqi wa ilaa Tareeqim Mustaqeem", english: "They said, \"O our people! We have heard a Book revealed after Moses, confirming what came before it: it guides (men) to the Truth and to a Straight Path", romanUrdu: "Unhon ne jaa kar kaha “aey hamari qaum ke logon, humne ek kitaab suni hai jo Moosa ke baad naazil ki gayi hai, tasdeeq(confirm) karne wali hai apne se pehle aayi hui kitaabon ki, rehnumayi karti hai haqq aur raah-e-raast ki taraf" },
    { number: 31, arabic: "يَٰقَوْمَنَآ أَجِيبُوا۟ دَاعِىَ ٱللَّهِ وَءَامِنُوا۟ بِهِۦ يَغْفِرْ لَكُم مِّن ذُنُوبِكُمْ وَيُجِرْكُم مِّنْ عَذَابٍ أَلِيمٍۢ", transliteration: "Ya qawmana ajeeboo daAAiya Allahi waaminoo bihi yaghfir lakum min thunoobikum wayujirkum min AAathabin aleemin", transliterationB: "Yaa qawmanaaa ajeeboo daa'iyal laahi wa aaminoo bihee yaghfir lakum min zunoobikum wa yujirkum min 'azaabin aleem", english: "O our people, hearken to the one who invites (you) to Allah, and believe in him: He will forgive you your faults, and deliver you from a Penalty Grievous", romanUrdu: "Aey hamari qaum ke logon, Allah ki taraf bulane waley ki dawat qabool karlo aur ispar imaan le aao, Allah tumhare gunaahon se darguzar famayega aur tumhein azaab e aleem se bacha dega”" },
    { number: 32, arabic: "وَمَن لَّا يُجِبْ دَاعِىَ ٱللَّهِ فَلَيْسَ بِمُعْجِزٍۢ فِى ٱلْأَرْضِ وَلَيْسَ لَهُۥ مِن دُونِهِۦٓ أَوْلِيَآءُ ۚ أُو۟لَٰٓئِكَ فِى ضَلَٰلٍۢ مُّبِينٍ", transliteration: "Waman la yujib daAAiya Allahi falaysa bimuAAjizin fee alardi walaysa lahu min doonihi awliyaa olaika fee dalalin mubeenin", transliterationB: "Wa mal laa yujib daa'iyal laahi falaisa bimu'jizin fil ardi wa laisa lahoo min dooniheee awliyaaa'; ulaaa ika fee dalaalim mubeen", english: "If any does not hearken to the one who invites (us) to Allah, he cannot frustrate (Allah's Plan) on earth, and no protectors can he have besides Allah: such men (wander) in manifest error", romanUrdu: "Aur jo koi Allah ke daai (one who calls to Allah) ki baat na maane woh na zameen mein khud koi bal boota rakhta hai ke Allah ko zach(frustrate) karde, aur na uske koi aise haami-o-sarparast (protector) hain ke Allah se usko bacha lein. Aisey log khuli gumraahi mein padey huey hain" },
    { number: 33, arabic: "أَوَلَمْ يَرَوْا۟ أَنَّ ٱللَّهَ ٱلَّذِى خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَلَمْ يَعْىَ بِخَلْقِهِنَّ بِقَٰدِرٍ عَلَىٰٓ أَن يُحْۦِىَ ٱلْمَوْتَىٰ ۚ بَلَىٰٓ إِنَّهُۥ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", transliteration: "Awalam yaraw anna Allaha allathee khalaqa alssamawati waalarda walam yaAAya bikhalqihinna biqadirin AAala an yuhyiya almawta bala innahu AAala kulli shayin qadeerun", transliterationB: "Awalam yaraw annal laahal lazee khalaqas samaawaati wal larda wa lam ya'ya bikhal qihinna biqaadirin 'alaaa anyyuhiyal mawtaa; balaaa innahoo 'alaa kulli shai'in Qadeer", english: "See they not that Allah, Who created the heavens and the earth, and never wearied with their creation, is able to give life to the dead? Yea, verily He has power over all things", romanUrdu: "Aur kya in logon ko yeh sujhayi nahin deta ke jis khuda ne yeh zameen aur aasmaan paida kiye hain aur inko banate huey jo na thaka, woh zaroor ispar qadir hai ke murdon (dead) ko jila uthaye? Kyun nahin, yaqeenan woh har cheez ki qudrat rakhta hai" },
    { number: 34, arabic: "وَيَوْمَ يُعْرَضُ ٱلَّذِينَ كَفَرُوا۟ عَلَى ٱلنَّارِ أَلَيْسَ هَٰذَا بِٱلْحَقِّ ۖ قَالُوا۟ بَلَىٰ وَرَبِّنَا ۚ قَالَ فَذُوقُوا۟ ٱلْعَذَابَ بِمَا كُنتُمْ تَكْفُرُونَ", transliteration: "Wayawma yuAAradu allatheena kafaroo AAala alnnari alaysa hatha bialhaqqi qaloo bala warabbina qala fathooqoo alAAathaba bima kuntum takfuroona", transliterationB: "Wa Yawma yu'radul lazeena kafaroo 'alan naari alaisa haaza bil haqq; qaaloo balaa wa Rabbinaa; qaala fazooqul 'azaaba bimaa kuntum takfuroon", english: "And on the Day that the Unbelievers will be placed before the Fire, (they will be asked,) \"Is this not the Truth?\" they will say, \"Yea, by our Lord!\" (One will say:) \"Then taste ye the Penalty, for that ye were wont to deny (Truth)", romanUrdu: "Jis roz yeh kaafir aag ke saamne laye jayenge , us waqt unsey pucha jayega “ kya yeh haqq nahin hai?” yeh kahenge “ haan, hamare Rubb ki kasam (yeh waqai haqq hai)” Allah farmayega “ accha to ab azaab ka mazaa chakkho apne us inkar ki padash mein jo tum karte rahe thay”" },
    { number: 35, arabic: "فَٱصْبِرْ كَمَا صَبَرَ أُو۟لُوا۟ ٱلْعَزْمِ مِنَ ٱلرُّسُلِ وَلَا تَسْتَعْجِل لَّهُمْ ۚ كَأَنَّهُمْ يَوْمَ يَرَوْنَ مَا يُوعَدُونَ لَمْ يَلْبَثُوٓا۟ إِلَّا سَاعَةًۭ مِّن نَّهَارٍۭ ۚ بَلَٰغٌۭ ۚ فَهَلْ يُهْلَكُ إِلَّا ٱلْقَوْمُ ٱلْفَٰسِقُونَ", transliteration: "Faisbir kama sabara oloo alAAazmi mina alrrusuli wala tastaAAjil lahum kaannahum yawma yarawna ma yooAAadoona lam yalbathoo illa saAAatan min naharin balaghun fahal yuhlaku illa alqawmu alfasiqoona", transliterationB: "Fasbir kamaa sabara ulul 'azmi minar Rusuli wa laa tasta'jil lahum; ka annahum Yawma yarawna maa yoo'adoona lam yalbasooo illaa saa'atam min nahaar; balaagh; fahal yuhlaku illal qawmul faasiqoon", english: "Therefore patiently persevere, as did (all) messengers of inflexible purpose; and be in no haste about the (Unbelievers). On the Day that they see the (Punishment) promised them, (it will be) as if they had not tarried more than an hour in a single day. (Thine but) to proclaim the Message: but shall any be destroyed except those who transgress", romanUrdu: "Pas aey Nabi, sabr karo jis tarhan ulul azm (strong will) Rasoolon ne sabr kiya hai, aur inke maamle mein jaldi na karo. Jis roz yeh log us cheez ko dekh lenge jiska inhein khauff dilaya ja raha hai to inhein yun maloon hoga ke jaise duniya mein din ki ek ghadi bhar se zyada nahin rahey thay. Baat pahuncha di gayi, ab kya nafarmaan logon ke siwa aur koi halak hoga" }
  ]
};
